using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetAllInvoicesAsync(InvoiceStatus? statusFilter = null)
    {
        var query = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (statusFilter.HasValue)
            query = query.Where(i => i.Status == statusFilter.Value);

        return await query.OrderByDescending(i => i.CreatedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceByIdAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task UpdateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddInvoiceItemAsync(int invoiceId, InvoiceItem item)
    {
        item.InvoiceId = invoiceId;
        db.InvoiceItems.Add(item);
        var invoice = await db.Invoices.Include(i => i.Items).FirstAsync(i => i.Id == invoiceId);
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice) + (item.Quantity * item.UnitPrice);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            var invoice = await db.Invoices.Include(i => i.Items).FirstAsync(i => i.Id == item.InvoiceId);
            invoice.TotalAmount = invoice.Items.Where(i => i.Id != itemId).Sum(i => i.Quantity * i.UnitPrice);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == payment.InvoiceId);
        var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int invoiceId)
    {
        return await db.Payments
            .Where(p => p.InvoiceId == invoiceId)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    public async Task<decimal> GetOutstandingBalanceAsync(int invoiceId)
    {
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == invoiceId);
        return invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount);
    }

    public async Task<int> GetOutstandingInvoiceCountAsync()
    {
        return await db.Invoices
            .Where(i => i.Status == InvoiceStatus.Sent || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
    }
}
