using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    public async Task<List<Pet>> GetAllPetsAsync(string? search = null)
    {
        var query = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(search) 
                || p.Owner.LastName.ToLower().Contains(search)
                || p.Owner.FirstName.ToLower().Contains(search));
        }
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Pet?> GetPetByIdAsync(int id)
    {
        return await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.DateTime))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<List<Owner>> GetAllOwnersAsync()
    {
        return await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerByIdAsync(int id)
    {
        return await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);
    }

    public async Task<Pet> CreatePetAsync(Pet pet)
    {
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task<Owner> CreateOwnerAsync(Owner owner)
    {
        db.Owners.Add(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task UpdatePetAsync(Pet pet)
    {
        db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task UpdateOwnerAsync(Owner owner)
    {
        db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task<List<TreatmentNote>> GetMedicalHistoryAsync(int petId)
    {
        return await db.TreatmentNotes
            .Where(t => t.PetId == petId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    public async Task<int> GetTotalPetsCountAsync()
    {
        return await db.Pets.CountAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsForWeekAsync(DateTime weekStart)
    {
        var weekEnd = weekStart.AddDays(7);
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.DateTime >= weekStart && a.DateTime < weekEnd)
            .OrderBy(a => a.DateTime)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetTodaysAppointmentsAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.DateTime >= today && a.DateTime < tomorrow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.DateTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentByIdAsync(int id)
    {
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task RescheduleAsync(int id, DateTime newDateTime)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.DateTime = newDateTime;
            await db.SaveChangesAsync();
        }
    }

    public async Task CancelAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableTimeSlotsAsync(DateTime date)
    {
        var startHour = 8;
        var endHour = 18;
        var allSlots = new List<DateTime>();
        for (var hour = startHour; hour < endHour; hour++)
        {
            allSlots.Add(date.Date.AddHours(hour));
            allSlots.Add(date.Date.AddHours(hour).AddMinutes(30));
        }

        var bookedSlots = await db.Appointments
            .Where(a => a.DateTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.DateTime)
            .ToListAsync();

        return allSlots.Where(s => !bookedSlots.Contains(s)).ToList();
    }

    public async Task<int> GetTodaysAppointmentCountAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        return await db.Appointments
            .Where(a => a.DateTime >= today && a.DateTime < tomorrow && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetAllInvoicesAsync(InvoiceStatus? statusFilter = null)
    {
        var query = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (statusFilter.HasValue)
            query = query.Where(i => i.Status == statusFilter.Value);

        return await query.OrderByDescending(i => i.CreatedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceByIdAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task UpdateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddInvoiceItemAsync(int invoiceId, InvoiceItem item)
    {
        item.InvoiceId = invoiceId;
        db.InvoiceItems.Add(item);
        var invoice = await db.Invoices.Include(i => i.Items).FirstAsync(i => i.Id == invoiceId);
        invoice.TotalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice) + (item.Quantity * item.UnitPrice);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            var invoice = await db.Invoices.Include(i => i.Items).FirstAsync(i => i.Id == item.InvoiceId);
            invoice.TotalAmount = invoice.Items.Where(i => i.Id != itemId).Sum(i => i.Quantity * i.UnitPrice);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == payment.InvoiceId);
        var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int invoiceId)
    {
        return await db.Payments
            .Where(p => p.InvoiceId == invoiceId)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    public async Task<decimal> GetOutstandingBalanceAsync(int invoiceId)
    {
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == invoiceId);
        return invoice.TotalAmount - invoice.Payments.Sum(p => p.Amount);
    }

    public async Task<int> GetOutstandingInvoiceCountAsync()
    {
        return await db.Invoices
            .Where(i => i.Status == InvoiceStatus.Sent || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
    }
}

