+using Microsoft.EntityFrameworkCore;
+using VetClinic.Data;
+using VetClinic.Data.Models;
+
+namespace VetClinic.Services;
+
+public class AppointmentService(ApplicationDbContext db)
+{
+    public async Task<List<Appointment>> GetAppointmentsForWeekAsync(DateTime weekStart)
+    {
+        var weekEnd = weekStart.AddDays(7);
+        return await db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Where(a => a.DateTime >= weekStart && a.DateTime < weekEnd)
+            .OrderBy(a => a.DateTime)
+            .ToListAsync();
+    }
+
+    public async Task<List<Appointment>> GetTodaysAppointmentsAsync()
+    {
+        var today = DateTime.Today;
+        var tomorrow = today.AddDays(1);
+        return await db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Where(a => a.DateTime >= today && a.DateTime < tomorrow && a.Status == AppointmentStatus.Scheduled)
+            .OrderBy(a => a.DateTime)
+            .ToListAsync();
+    }
+
+    public async Task<Appointment?> GetAppointmentByIdAsync(int id)
+    {
+        return await db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .FirstOrDefaultAsync(a => a.Id == id);
+    }
+
+    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
+    {
+        db.Appointments.Add(appointment);
+        await db.SaveChangesAsync();
+        return appointment;
+    }
+
+    public async Task UpdateAppointmentAsync(Appointment appointment)
+    {
+        db.Appointments.Update(appointment);
+        await db.SaveChangesAsync();
+    }
+
+    public async Task RescheduleAsync(int id, DateTime newDateTime)
+    {
+        var appointment = await db.Appointments.FindAsync(id);
+        if (appointment != null)
+        {
+            appointment.DateTime = newDateTime;
+            await db.SaveChangesAsync();
+        }
+    }
+
+    public async Task CancelAsync(int id)
+    {
+        var appointment = await db.Appointments.FindAsync(id);
+        if (appointment != null)
+        {
+            appointment.Status = AppointmentStatus.Cancelled;
+            await db.SaveChangesAsync();
+        }
+    }
+
+    public async Task<List<DateTime>> GetAvailableTimeSlotsAsync(DateTime date)
+    {
+        var startHour = 8;
+        var endHour = 18;
+        var allSlots = new List<DateTime>();
+        for (var hour = startHour; hour < endHour; hour++)
+        {
+            allSlots.Add(date.Date.AddHours(hour));
+            allSlots.Add(date.Date.AddHours(hour).AddMinutes(30));
+        }
+
+        var bookedSlots = await db.Appointments
+            .Where(a => a.DateTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
+            .Select(a => a.DateTime)
+            .ToListAsync();
+
+        return allSlots.Where(s => !bookedSlots.Contains(s)).ToList();
+    }
+
+    public async Task<int> GetTodaysAppointmentCountAsync()
+    {
+        var today = DateTime.Today;
+        var tomorrow = today.AddDays(1);
+        return await db.Appointments
+            .Where(a => a.DateTime >= today && a.DateTime < tomorrow && a.Status == AppointmentStatus.Scheduled)
+            .CountAsync();
+    }
+}
