@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]

@inject PatientService PatientService
@inject AppointmentService AppointmentService
@inject BillingService BillingService
@inject NavigationManager Navigation

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="card-text display-6">@totalPatients</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todaysAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Outstanding Invoices</h5>
                <p class="card-text display-6">@outstandingInvoices</p>
            </div>
        </div>
    </div>
</div>

<div class="row mb-4">
    <div class="col-12">
        <h5>Quick Actions</h5>
        <button class="btn btn-primary me-2" @onclick="() => Navigation.NavigateTo("/patients?register=true")">
            <span class="bi bi-plus-circle"></span> Register Pet
        </button>
        <button class="btn btn-success me-2" @onclick="() => Navigation.NavigateTo("/appointments?create=true")">
            <span class="bi bi-calendar-plus"></span> Create Appointment
        </button>
        <button class="btn btn-warning me-2" @onclick="() => Navigation.NavigateTo("/billing?create=true")">
            <span class="bi bi-receipt"></span> Create Invoice
        </button>
    </div>
</div>

<div class="row">
    <div class="col-12">
        <h5>Today's Appointments</h5>
        @if (todaysAppointmentList == null)
        {
            <p>Loading...</p>
        }
        else if (!todaysAppointmentList.Any())
        {
            <p class="text-muted">No appointments scheduled for today.</p>
        }
        else
        {
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Pet</th>
                        <th>Owner</th>
                        <th>Reason</th>
                        <th>Staff</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var apt in todaysAppointmentList)
                    {
                        <tr>
                            <td>@apt.DateTime.ToString("h:mm tt")</td>
