                                <small class="text-muted">Staff: @note.StaffName</small>
                            </div>
                        </div>
                    }
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Pet? pet;
    private TreatmentNote newNote = new() { Date = DateTime.Now };
    private string? message;

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientService.GetPetByIdAsync(Id);
    }

    private async Task SavePetAsync()
    {
        if (pet != null)
        {
            await PatientService.UpdatePetAsync(pet);
            message = "Pet updated successfully.";
        }
    }

    private async Task SaveOwnerAsync()
    {
        if (pet?.Owner != null)
        {
            await PatientService.UpdateOwnerAsync(pet.Owner);
            message = "Owner updated successfully.";
        }
    }

    private async Task AddNoteAsync()
    {
        if (pet != null)
        {
            newNote.PetId = pet.Id;
            await PatientService.AddTreatmentNoteAsync(newNote);
            pet = await PatientService.GetPetByIdAsync(Id);
            newNote = new() { Date = DateTime.Now };
        }
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="btn-group">
            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&lt; Previous</button>
            <button class="btn btn-outline-secondary" @onclick="() => weekStart = GetWeekStart(DateTime.Today)">Today</button>
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &gt;</button>
        </div>
        <span class="ms-3 fw-bold">@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</span>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="() => ShowCreateForm()">Create Appointment</button>
    </div>
</div>

@if (showForm)
{
    <AppointmentForm Pet="selectedPet" Pets="allPets" Appointment="editingAppointment" 
                     AvailableSlots="availableSlots" OnDateChanged="OnDateChangedAsync"
                     OnSave="SaveAppointmentAsync" OnCancel="() => showForm = false" />
}

<div class="row">
    @for (int d = 0; d < 7; d++)
    {
        var day = weekStart.AddDays(d);
        var dayAppointments = appointments?.Where(a => a.DateTime.Date == day.Date).ToList() ?? new();
        <div class="col">
            <div class="card">
                <div class="card-header text-center @(day.Date == DateTime.Today ? "bg-primary text-white" : "")">
                    <strong>@day.ToString("ddd")</strong><br />
                    <small>@day.ToString("MMM dd")</small>
                </div>
                <div class="card-body p-1" style="min-height: 300px; font-size: 0.8rem;">
                    @foreach (var apt in dayAppointments)
                    {
                        var bgColor = apt.Status switch
                        {
                            AppointmentStatus.Scheduled => "bg-info",
                            AppointmentStatus.Completed => "bg-success",
                            AppointmentStatus.Cancelled => "bg-secondary",
                            AppointmentStatus.NoShow => "bg-danger",
                            _ => "bg-light"
                        };
                        <div class="@bgColor text-white rounded p-1 mb-1" style="cursor:pointer" 
                             @onclick="() => EditAppointment(apt)">
                            <strong>@apt.DateTime.ToString("h:mm tt")</strong><br />
                            @apt.Pet.Name - @apt.Reason
                        </div>
                    }
                </div>
            </div>
        </div>
    }
</div>

@if (editingExisting != null)
{
    <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5>Appointment: @editingExisting.Pet.Name</h5>
                    <button type="button" class="btn-close" @onclick="() => editingExisting = null"></button>
                </div>
                <div class="modal-body">
                    <p><strong>Time:</strong> @editingExisting.DateTime.ToString("g")</p>
                    <p><strong>Reason:</strong> @editingExisting.Reason</p>
                    <p><strong>Status:</strong> @editingExisting.Status</p>
                    <p><strong>Staff:</strong> @editingExisting.StaffName</p>
                    <p><strong>Notes:</strong> @editingExisting.Notes</p>

                    <div class="mb-2">
                        <label class="form-label">Reschedule to:</label>
                        <input type="datetime-local" class="form-control" @bind="rescheduleDate" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-warning" @onclick="RescheduleAsync">Reschedule</button>
                    <button class="btn btn-danger" @onclick="CancelAppointmentAsync">Cancel Appointment</button>
                    <button class="btn btn-secondary" @onclick="() => editingExisting = null">Close</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private DateTime weekStart;
    private List<Appointment>? appointments;
    private List<Pet> allPets = new();
    private bool showForm;
    private Appointment editingAppointment = new();
    private Appointment? editingExisting;
    private Pet? selectedPet;
    private List<DateTime> availableSlots = new();
    private DateTime rescheduleDate = DateTime.Now;

    [SupplyParameterFromQuery]
    public string? Create { get; set; }

    [SupplyParameterFromQuery]
    public int? PetId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        weekStart = GetWeekStart(DateTime.Today);
        await LoadAppointmentsAsync();
        allPets = await PatientService.GetAllPetsAsync();

        if (Create == "true")
        {
            ShowCreateForm();
            if (PetId.HasValue)
            {
                editingAppointment.PetId = PetId.Value;
            }
        }
    }

    private DateTime GetWeekStart(DateTime date) => date.AddDays(-(int)date.DayOfWeek + (int)DayOfWeek.Monday);

    private async Task LoadAppointmentsAsync()
    {
        appointments = await AppointmentService.GetAppointmentsForWeekAsync(weekStart);
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        await LoadAppointmentsAsync();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        await LoadAppointmentsAsync();
    }

    private void ShowCreateForm()
    {
        editingAppointment = new Appointment { DateTime = DateTime.Today.AddHours(9), DurationMinutes = 30 };
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingExisting = apt;
        rescheduleDate = apt.DateTime;
    }

    private async Task OnDateChangedAsync(DateTime date)
    {
        availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(date);
    }

    private async Task SaveAppointmentAsync(Appointment appointment)
    {
        await AppointmentService.CreateAppointmentAsync(appointment);
        showForm = false;
        await LoadAppointmentsAsync();
    }

    private async Task RescheduleAsync()
    {
        if (editingExisting != null)
        {
            await AppointmentService.RescheduleAsync(editingExisting.Id, rescheduleDate);
            editingExisting = null;
            await LoadAppointmentsAsync();
        }
    }

    private async Task CancelAppointmentAsync()
    {
        if (editingExisting != null)
        {
            await AppointmentService.CancelAsync(editingExisting.Id);
            editingExisting = null;
            await LoadAppointmentsAsync();
        }
    }
}

@using VetClinic.Data.Models

<div class="card mb-4">
    <div class="card-header">@(Appointment.Id == 0 ? "Create" : "Edit") Appointment</div>
    <div class="card-body">
        <EditForm Model="Appointment" OnValidSubmit="HandleSubmit" FormName="AppointmentForm">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Pet</label>
                    <InputSelect class="form-select" @bind-Value="Appointment.PetId">
                        <option value="0">-- Select Pet --</option>
                        @if (Pets != null)
                        {
                            @foreach (var pet in Pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                            }
                        }
                    </InputSelect>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Date</label>
                    <InputDate class="form-control" @bind-Value="selectedDate" @bind-Value:after="DateChanged" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Time Slot</label>
                    @if (AvailableSlots != null && AvailableSlots.Any())
                    {
                        <InputSelect class="form-select" @bind-Value="selectedTime">
                            @foreach (var slot in AvailableSlots)
                            {
                                <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt")</option>
                            }
                        </InputSelect>
                    }
                    else
                    {
                        <input type="time" class="form-control" @bind="selectedTime" />
                    }
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Duration (minutes)</label>
                    <InputNumber class="form-control" @bind-Value="Appointment.DurationMinutes" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Reason</label>
                    <InputText class="form-control" @bind-Value="Appointment.Reason" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Staff Name</label>
                    <InputText class="form-control" @bind-Value="Appointment.StaffName" />
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="Appointment.Notes" />
            </div>

            <button type="submit" class="btn btn-success me-2">Save</button>
            <button type="button" class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
        </EditForm>
    </div>
</div>

@code {
    [Parameter] public Appointment Appointment { get; set; } = new();
    [Parameter] public List<Pet>? Pets { get; set; }
    [Parameter] public Pet? Pet { get; set; }
    [Parameter] public List<DateTime>? AvailableSlots { get; set; }
    [Parameter] public EventCallback<DateTime> OnDateChanged { get; set; }
    [Parameter] public EventCallback<Appointment> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private DateTime selectedDate = DateTime.Today;
    private string selectedTime = "09:00";

    protected override void OnParametersSet()
    {
        if (Appointment.DateTime != default)
        {
            selectedDate = Appointment.DateTime.Date;
            selectedTime = Appointment.DateTime.ToString("HH:mm");
        }
    }

    private async Task DateChanged()
    {
        await OnDateChanged.InvokeAsync(selectedDate);
    }

    private async Task HandleSubmit()
    {
        if (TimeSpan.TryParse(selectedTime, out var time))
        {
            Appointment.DateTime = selectedDate.Date + time;
        }
        await OnSave.InvokeAsync(Appointment);
    }
}

@page "/billing"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]

@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="btn-group">
            <button class="btn @(statusFilter == null ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterAsync(null)">All</button>
            <button class="btn @(statusFilter == InvoiceStatus.Draft ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterAsync(InvoiceStatus.Draft)">Draft</button>
            <button class="btn @(statusFilter == InvoiceStatus.Sent ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterAsync(InvoiceStatus.Sent)">Sent</button>
            <button class="btn @(statusFilter == InvoiceStatus.Paid ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterAsync(InvoiceStatus.Paid)">Paid</button>
            <button class="btn @(statusFilter == InvoiceStatus.Overdue ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterAsync(InvoiceStatus.Overdue)">Overdue</button>
        </div>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowCreateForm">Create Invoice</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create Invoice</div>
        <div class="card-body">
            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoice.PetId">
                        <option value="0">-- Select Pet --</option>
                        @foreach (var pet in allPets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="newInvoice.DueDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Notes</label>
                    <input type="text" class="form-control" @bind="newInvoice.Notes" />
                </div>
            </div>

            <h6>Line Items</h6>
            @foreach (var item in newItems)
            {
                <div class="row mb-1">
                    <div class="col-md-4">
                        <input type="text" class="form-control" placeholder="Description" @bind="item.Description" />
                    </div>
                    <div class="col-md-2">
                        <input type="number" class="form-control" placeholder="Qty" @bind="item.Quantity" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" class="form-control" placeholder="Unit Price" @bind="item.UnitPrice" step="0.01" />
                    </div>
                    <div class="col-md-2">
                        <span class="form-control-plaintext">@((item.Quantity * item.UnitPrice).ToString("C"))</span>
                    </div>
                    <div class="col-md-1">
                        <button class="btn btn-sm btn-danger" @onclick="() => newItems.Remove(item)">X</button>
                    </div>
                </div>
            }
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="() => newItems.Add(new InvoiceItem { Quantity = 1 })">+ Add Item</button>

            <div class="mb-2">
                <strong>Total: @newItems.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</strong>
            </div>

            <button class="btn btn-success me-2" @onclick="CreateInvoiceAsync">Create</button>
            <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
        </div>
    </div>
}

@if (invoices == null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr>
                <th>#</th>
                <th>Pet</th>
                <th>Owner</th>
                <th>Date</th>
                <th>Total</th>
                <th>Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var invoice in invoices)
            {
                <tr style="cursor:pointer" @onclick="() => Navigation.NavigateTo($"/billing/{invoice.Id}")">
                    <td>@invoice.Id</td>
                    <td>@invoice.Pet.Name</td>
                    <td>@invoice.Pet.Owner.FirstName @invoice.Pet.Owner.LastName</td>
                    <td>@invoice.CreatedDate.ToString("MMM dd, yyyy")</td>
                    <td>@invoice.TotalAmount.ToString("C")</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(invoice.Status)">@invoice.Status</span>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Invoice>? invoices;
    private List<Pet> allPets = new();
    private InvoiceStatus? statusFilter;
    private bool showCreateForm;
    private Invoice newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
    private List<InvoiceItem> newItems = new() { new InvoiceItem { Quantity = 1 } };

    [SupplyParameterFromQuery]
    public string? Create { get; set; }

    [SupplyParameterFromQuery]
    public int? PetId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        allPets = await PatientService.GetAllPetsAsync();
        await LoadInvoicesAsync();

        if (Create == "true")
        {
            showCreateForm = true;
            if (PetId.HasValue)
                newInvoice.PetId = PetId.Value;
        }
    }

    private async Task LoadInvoicesAsync()
    {
        invoices = await BillingService.GetAllInvoicesAsync(statusFilter);
    }

    private async Task FilterAsync(InvoiceStatus? status)
    {
        statusFilter = status;
        await LoadInvoicesAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newInvoice = new Invoice { DueDate = DateTime.Today.AddDays(30) };
        newItems = new List<InvoiceItem> { new InvoiceItem { Quantity = 1 } };
    }

    private async Task CreateInvoiceAsync()
    {
        newInvoice.Items = newItems;
        await BillingService.CreateInvoiceAsync(newInvoice);
        showCreateForm = false;
        await LoadInvoicesAsync();
    }

    private string GetStatusBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Sent => "bg-info",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-light"
    };
}

