+@page "/appointments"
+@using Microsoft.AspNetCore.Authorization
+@using VetClinic.Data.Models
+@using VetClinic.Services
+@attribute [Authorize]
+
+@inject AppointmentService AppointmentService
+@inject PatientService PatientService
+@inject NavigationManager Navigation
+
+<PageTitle>Appointments - VetClinic</PageTitle>
+
+<h1>Appointments</h1>
+
+<div class="row mb-3">
+    <div class="col-md-6">
+        <div class="btn-group">
+            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&lt; Previous</button>
+            <button class="btn btn-outline-secondary" @onclick="() => weekStart = GetWeekStart(DateTime.Today)">Today</button>
+            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &gt;</button>
+        </div>
+        <span class="ms-3 fw-bold">@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</span>
+    </div>
+    <div class="col-md-6 text-end">
+        <button class="btn btn-primary" @onclick="() => ShowCreateForm()">Create Appointment</button>
+    </div>
+</div>
+
+@if (showForm)
+{
+    <AppointmentForm Pet="selectedPet" Pets="allPets" Appointment="editingAppointment" 
+                     AvailableSlots="availableSlots" OnDateChanged="OnDateChangedAsync"
+                     OnSave="SaveAppointmentAsync" OnCancel="() => showForm = false" />
+}
+
+<div class="row">
+    @for (int d = 0; d < 7; d++)
+    {
+        var day = weekStart.AddDays(d);
+        var dayAppointments = appointments?.Where(a => a.DateTime.Date == day.Date).ToList() ?? new();
+        <div class="col">
+            <div class="card">
+                <div class="card-header text-center @(day.Date == DateTime.Today ? "bg-primary text-white" : "")">
+                    <strong>@day.ToString("ddd")</strong><br />
+                    <small>@day.ToString("MMM dd")</small>
+                </div>
+                <div class="card-body p-1" style="min-height: 300px; font-size: 0.8rem;">
+                    @foreach (var apt in dayAppointments)
+                    {
+                        var bgColor = apt.Status switch
+                        {
+                            AppointmentStatus.Scheduled => "bg-info",
+                            AppointmentStatus.Completed => "bg-success",
+                            AppointmentStatus.Cancelled => "bg-secondary",
+                            AppointmentStatus.NoShow => "bg-danger",
+                            _ => "bg-light"
+                        };
+                        <div class="@bgColor text-white rounded p-1 mb-1" style="cursor:pointer" 
+                             @onclick="() => EditAppointment(apt)">
+                            <strong>@apt.DateTime.ToString("h:mm tt")</strong><br />
+                            @apt.Pet.Name - @apt.Reason
+                        </div>
+                    }
+                </div>
+            </div>
+        </div>
+    }
+</div>
+
+@if (editingExisting != null)
+{
+    <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
+        <div class="modal-dialog">
+            <div class="modal-content">
+                <div class="modal-header">
+                    <h5>Appointment: @editingExisting.Pet.Name</h5>
+                    <button type="button" class="btn-close" @onclick="() => editingExisting = null"></button>
+                </div>
+                <div class="modal-body">
+                    <p><strong>Time:</strong> @editingExisting.DateTime.ToString("g")</p>
+                    <p><strong>Reason:</strong> @editingExisting.Reason</p>
+                    <p><strong>Status:</strong> @editingExisting.Status</p>
+                    <p><strong>Staff:</strong> @editingExisting.StaffName</p>
+                    <p><strong>Notes:</strong> @editingExisting.Notes</p>
+
+                    <div class="mb-2">
+                        <label class="form-label">Reschedule to:</label>
+                        <input type="datetime-local" class="form-control" @bind="rescheduleDate" />
+                    </div>
+                </div>
+                <div class="modal-footer">
+                    <button class="btn btn-warning" @onclick="RescheduleAsync">Reschedule</button>
+                    <button class="btn btn-danger" @onclick="CancelAppointmentAsync">Cancel Appointment</button>
+                    <button class="btn btn-secondary" @onclick="() => editingExisting = null">Close</button>
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@code {
+    private DateTime weekStart;
+    private List<Appointment>? appointments;
+    private List<Pet> allPets = new();
+    private bool showForm;
+    private Appointment editingAppointment = new();
+    private Appointment? editingExisting;
+    private Pet? selectedPet;
+    private List<DateTime> availableSlots = new();
+    private DateTime rescheduleDate = DateTime.Now;
+
+    [SupplyParameterFromQuery]
+    public string? Create { get; set; }
+
+    [SupplyParameterFromQuery]
+    public int? PetId { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        weekStart = GetWeekStart(DateTime.Today);
+        await LoadAppointmentsAsync();
+        allPets = await PatientService.GetAllPetsAsync();
+
+        if (Create == "true")
+        {
+            ShowCreateForm();
+            if (PetId.HasValue)
+            {
+                editingAppointment.PetId = PetId.Value;
+            }
+        }
+    }
+
+    private DateTime GetWeekStart(DateTime date) => date.AddDays(-(int)date.DayOfWeek + (int)DayOfWeek.Monday);
+
+    private async Task LoadAppointmentsAsync()
+    {
+        appointments = await AppointmentService.GetAppointmentsForWeekAsync(weekStart);
+    }
+
+    private async Task PreviousWeek()
+    {
+        weekStart = weekStart.AddDays(-7);
+        await LoadAppointmentsAsync();
+    }
+
+    private async Task NextWeek()
+    {
+        weekStart = weekStart.AddDays(7);
+        await LoadAppointmentsAsync();
+    }
+
+    private void ShowCreateForm()
+    {
+        editingAppointment = new Appointment { DateTime = DateTime.Today.AddHours(9), DurationMinutes = 30 };
+        showForm = true;
+    }
+
+    private void EditAppointment(Appointment apt)
+    {
+        editingExisting = apt;
+        rescheduleDate = apt.DateTime;
+    }
+
+    private async Task OnDateChangedAsync(DateTime date)
+    {
+        availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(date);
+    }
+
+    private async Task SaveAppointmentAsync(Appointment appointment)
+    {
+        await AppointmentService.CreateAppointmentAsync(appointment);
+        showForm = false;
+        await LoadAppointmentsAsync();
+    }
+
+    private async Task RescheduleAsync()
+    {
+        if (editingExisting != null)
+        {
+            await AppointmentService.RescheduleAsync(editingExisting.Id, rescheduleDate);
+            editingExisting = null;
+            await LoadAppointmentsAsync();
+        }
+    }
+
+    private async Task CancelAppointmentAsync()
+    {
+        if (editingExisting != null)
+        {
+            await AppointmentService.CancelAsync(editingExisting.Id);
+            editingExisting = null;
+            await LoadAppointmentsAsync();
+        }
+    }
+}
+

